import{c as a,Q as e,j as s,m as d}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Claude Codeでハーネスエンジニアリングを実践する — 5層の設計パターン","description":"","frontmatter":{"title":"Claude Codeでハーネスエンジニアリングを実践する — 5層の設計パターン","date":"2026-04-15T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-15-claude-code-harness-engineering-zenn-sasadango.md","filePath":"research/ai-articles/scored/2026-04-15-claude-code-harness-engineering-zenn-sasadango.md","lastUpdated":1779894392000}'),i={name:"research/ai-articles/scored/2026-04-15-claude-code-harness-engineering-zenn-sasadango.md"};function n(l,t,r,o,h,c){return e(),s("div",null,[...t[0]||(t[0]=[d(`<blockquote><p>Source: <a href="https://zenn.dev/sasadango28/articles/claude-code-harness-engineering-20260415" target="_blank" rel="noreferrer">https://zenn.dev/sasadango28/articles/claude-code-harness-engineering-20260415</a> Fetched: 2026-05-08</p></blockquote><h1 id="claude-codeでハーネスエンジニアリングを実践する-—-5層の設計パターン" tabindex="-1">Claude Codeでハーネスエンジニアリングを実践する — 5層の設計パターン <a class="header-anchor" href="#claude-codeでハーネスエンジニアリングを実践する-—-5層の設計パターン" aria-label="Permalink to &quot;Claude Codeでハーネスエンジニアリングを実践する — 5層の設計パターン&quot;">​</a></h1><h2 id="はじめに" tabindex="-1">はじめに <a class="header-anchor" href="#はじめに" aria-label="Permalink to &quot;はじめに&quot;">​</a></h2><p>Claude Codeを効果的に運用するには、プロンプト作成だけでは不十分です。AIの動作を環境側で設計・管理する「ハーネスエンジニアリング」というアプローチがあります。CLAUDE.md、Skills、Agents、Hooks、Settingsといった複数の仕組みを組み合わせることで、AIエージェントを意図した方向に動かせます。</p><p>著者は個人用のナレッジ管理リポジトリでこの設計パターンを実践しており、その知見を紹介する記事です。</p><h2 id="ハーネスエンジニアリングとは" tabindex="-1">ハーネスエンジニアリングとは <a class="header-anchor" href="#ハーネスエンジニアリングとは" aria-label="Permalink to &quot;ハーネスエンジニアリングとは&quot;">​</a></h2><h3 id="概念の成り立ち" tabindex="-1">概念の成り立ち <a class="header-anchor" href="#概念の成り立ち" aria-label="Permalink to &quot;概念の成り立ち&quot;">​</a></h3><p>ハーネスエンジニアリングはHashiCorp共同創業者のMitchell Hashimotoが2026年2月のブログで提唱した概念です。「エージェントがミスをするたびに、同じ失敗を繰り返さないよう環境側に恒久的な修正を施す」という思想に基づいています。</p><p>この概念はOpenAIやAnthropicなど主要企業により発展させられ、Martin Fowlerはフィードフォワード制御（Guide）とフィードバック制御（Sensor）の枠組みで体系化しました。</p><h3 id="llmの本質とハーネスの必要性" tabindex="-1">LLMの本質とハーネスの必要性 <a class="header-anchor" href="#llmの本質とハーネスの必要性" aria-label="Permalink to &quot;LLMの本質とハーネスの必要性&quot;">​</a></h3><p>LLMは本質的に「ステートレスな関数」です。推論中にモデルの重みは変わらず、内部に記憶機能がありません。同じ入力でも出力が異なるのはサンプリング時の確率的ゆらぎに起因します。</p><p>重要な点として、「LLMは推論中に何も覚えない」という特性があります。会話が続いているように見えるのは、アプリケーション層が毎回全会話履歴をプロンプトに含めているからです。つまり、毎回がLLMにとって初対面の状態です。</p><p>プロジェクトのルール、過去の失敗事例、ディレクトリ構成など、すべてを毎回外部から注入する必要があります。この注入の仕組み全体を設計することがハーネスエンジニアリングです。</p><h3 id="_3つのエンジニアリングの位置づけ" tabindex="-1">3つのエンジニアリングの位置づけ <a class="header-anchor" href="#_3つのエンジニアリングの位置づけ" aria-label="Permalink to &quot;3つのエンジニアリングの位置づけ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>概念</th><th>対象</th><th>焦点</th></tr></thead><tbody><tr><td>プロンプトエンジニアリング</td><td>モデルへの入力テキスト</td><td>「何を聞くか」の最適化</td></tr><tr><td>コンテキストエンジニアリング</td><td>モデルに渡す情報全体</td><td>「何を見せるか」の最適化</td></tr><tr><td>ハーネスエンジニアリング</td><td>モデルの外側の実行環境全体</td><td>「どう動かすか」の最適化</td></tr></tbody></table><p>コンテキストエンジニアリングはハーネスの一部です。</p><h2 id="claude-codeにおけるハーネスの構成要素" tabindex="-1">Claude Codeにおけるハーネスの構成要素 <a class="header-anchor" href="#claude-codeにおけるハーネスの構成要素" aria-label="Permalink to &quot;Claude Codeにおけるハーネスの構成要素&quot;">​</a></h2><table tabindex="0"><thead><tr><th>要素</th><th>役割</th><th>ファイル</th></tr></thead><tbody><tr><td>CLAUDE.md</td><td>プロジェクト全体のルール・コンテキスト</td><td><code>CLAUDE.md</code></td></tr><tr><td>Rules</td><td>特定領域のドメインルール</td><td><code>.claude/rules/*.md</code></td></tr><tr><td>Skills</td><td>再利用可能なワークフロー定義</td><td><code>.claude/skills/*/SKILL.md</code></td></tr><tr><td>Agents</td><td>専門特化したサブエージェント</td><td><code>.claude/agents/*.md</code></td></tr><tr><td>Settings</td><td>ツール権限・セキュリティ制御</td><td><code>.claude/settings.json</code></td></tr></tbody></table><p>これらは層として積み重なってClaude Codeの動作を制御します。</p><h2 id="_5層の実装レイヤー" tabindex="-1">5層の実装レイヤー <a class="header-anchor" href="#_5層の実装レイヤー" aria-label="Permalink to &quot;5層の実装レイヤー&quot;">​</a></h2><h3 id="layer-1-claude-md-—-プロジェクトの「憲法」" tabindex="-1">Layer 1: CLAUDE.md — プロジェクトの「憲法」 <a class="header-anchor" href="#layer-1-claude-md-—-プロジェクトの「憲法」" aria-label="Permalink to &quot;Layer 1: CLAUDE.md — プロジェクトの「憲法」&quot;">​</a></h3><p>CLAUDE.mdはClaude Codeが最初に読み込む指示書です。プロジェクトの目的、ディレクトリ構成、技術スタック、守るべきルールを記述します。</p><p>著者のリポジトリでは以下を記載しています：</p><ul><li>リポジトリの目的（情報管理と意思決定支援の2軸）</li><li>ディレクトリ構成と配置指針</li><li>やらないこと（意思決定自動化、ファイル整理自動化など）</li><li>技術ルール（Python実行は<code>uv run</code>で、パッケージバージョン固定）</li><li>セキュリティルール（APIキーのハードコーディング禁止など）</li></ul><p>重要なのは「やらないこと」を明記することです。これは推論の抑制ではなく、行動スコープの定義です。境界線があるだけで、不要な変更が劇的に減ります。</p><h4 id="個人設定のimport方式" tabindex="-1">個人設定のimport方式 <a class="header-anchor" href="#個人設定のimport方式" aria-label="Permalink to &quot;個人設定のimport方式&quot;">​</a></h4><p>チーム開発ではCLAUDE.mdがgit管理されるため、個人の好みを直接書き込めません。CLAUDE.mdの末尾に以下を追加できます：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@my-preferences.md</span></span></code></pre></div><p><code>my-preferences.md</code>を<code>.gitignore</code>に追加すれば、各メンバーが個人設定を管理できます。参照先ファイルが存在しない場合は無視されるため、まだファイルを作っていないメンバーに影響はありません。</p><h3 id="layer-2-rules-—-ドメイン特化のルールブック" tabindex="-1">Layer 2: Rules — ドメイン特化のルールブック <a class="header-anchor" href="#layer-2-rules-—-ドメイン特化のルールブック" aria-label="Permalink to &quot;Layer 2: Rules — ドメイン特化のルールブック&quot;">​</a></h3><p><code>.claude/rules/</code>にMarkdownファイルを置くと、Claude Codeが自動的に読み込みます。CLAUDE.mdの肥大化を防ぎ、ドメインごとにルールを分離できます。</p><p>読み込みタイミングはフロントマターの<code>globs</code>指定で変わります：</p><table tabindex="0"><thead><tr><th>条件</th><th>読み込みタイミング</th><th>コンテキスト消費</th></tr></thead><tbody><tr><td><code>globs</code>なし</td><td>セッション開始時に常時ロード</td><td>常時</td></tr><tr><td><code>globs</code>あり</td><td>マッチするファイルを読んだ時点で遅延ロード</td><td>条件付き</td></tr></tbody></table><p>例：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">API層のコーディングルール</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">globs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;src/api/**/*.ts&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><p>著者は以下の2つのルールファイルを運用しています：</p><ul><li><strong>github_projects.md</strong> — タスク管理ルール（カンバン構成、粒度、利用方法）</li><li><strong>output_format.md</strong> — 出力ルール（命名規則、ファイル構成、データ形式）</li></ul><h3 id="layer-3-skills-—-再利用可能なワークフロー" tabindex="-1">Layer 3: Skills — 再利用可能なワークフロー <a class="header-anchor" href="#layer-3-skills-—-再利用可能なワークフロー" aria-label="Permalink to &quot;Layer 3: Skills — 再利用可能なワークフロー&quot;">​</a></h3><p>Skillsは<code>/コマンド名</code>で呼び出せるワークフロー定義です。SKILL.mdにMarkdownでプロンプトを書くだけで複雑な手順を実行できます。</p><p>著者のリポジトリでは13個のスキルを運用しており、代表例は：</p><p><strong>情報収集系：</strong></p><ul><li><code>/tech-daily2</code> — Pythonで事前収集し、LLMは翻訳・分類のみ</li><li><code>/new-books</code> — 技術書新刊を出版社ベースでチェック</li><li><code>/career-research</code> — 日本市場の企業リサーチ</li></ul><p><strong>深掘り・分析系：</strong></p><ul><li><code>/company-research</code> — 企業調査とEDINET財務分析</li><li><code>/pdf-translate</code> — PDF処理と日英翻訳</li></ul><p><strong>ナレッジ管理系：</strong></p><ul><li><code>/rag-index</code> — MarkdownをDuckDBにembedding格納</li><li><code>/rag-ask</code> — RAGインデックスをベクトル検索</li></ul><p>重要な設計原則は、「決定的な処理をスクリプトに、判断と生成をLLMに」という責務分離です。初期版の<code>tech-daily</code>ではすべてをLLMに任せていましたが、改善版の<code>tech-daily2</code>ではPythonスクリプトがRSS取得・パースを行い、LLMは翻訳と分類だけを担当します。結果、トークン消費が1/6、処理時間が1/3に削減されました。</p><h3 id="layer-4-agents-—-専門特化のサブエージェント" tabindex="-1">Layer 4: Agents — 専門特化のサブエージェント <a class="header-anchor" href="#layer-4-agents-—-専門特化のサブエージェント" aria-label="Permalink to &quot;Layer 4: Agents — 専門特化のサブエージェント&quot;">​</a></h3><p>Agentsは<code>@名前</code>で呼び出す、特定役割に特化したサブエージェントです。メインのClaude Codeとは別のコンテキストで動作するため、大量情報を扱うタスクでもメインコンテキストを汚しません。</p><p>著者のリポジトリでは、リポジトリ内の蓄積情報を横断検索・要約する専門エージェントを運用しています。曖昧な問い（「〜について何かあったっけ？」）に対応できます。</p><p>利点はコンテキスト分離です。数百ファイルを検索する場合、メインコンテキストで実行するとウィンドウが埋まってしまいますが、エージェント委譲なら要約だけが返ってきます。</p><h3 id="layer-5-settings-—-権限とセキュリティの制御" tabindex="-1">Layer 5: Settings — 権限とセキュリティの制御 <a class="header-anchor" href="#layer-5-settings-—-権限とセキュリティの制御" aria-label="Permalink to &quot;Layer 5: Settings — 権限とセキュリティの制御&quot;">​</a></h3><p><code>settings.json</code>でツールの使用権限を制御します。これはハーネスの「安全装置」です。</p><p>例：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;permissions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;allow&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(gh issue *)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(gh project *)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(jq *)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(uv run*python3 .claude/skills/*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;WebSearch&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;WebFetch&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Write&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;deny&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(gh repo delete*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(gh repo archive*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(gh pr close*)&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>設計ポイント：</p><ul><li><strong>allowは業務に必要な範囲で広く</strong> — 頻繁に使うコマンドは許可して作業のリズムを保つ</li><li><strong>denyは破壊的操作を明示的に禁止</strong> — リポジトリ削除やアーカイブなどを防ぐ</li><li><strong>settings.jsonとsettings.local.jsonの使い分け</strong> — 汎用ツールはgit共有、URL固定のcurlコマンドはローカル専用</li></ul><h2 id="設計で学んだこと" tabindex="-1">設計で学んだこと <a class="header-anchor" href="#設計で学んだこと" aria-label="Permalink to &quot;設計で学んだこと&quot;">​</a></h2><h3 id="「やらないこと」を定義する重要性" tabindex="-1">「やらないこと」を定義する重要性 <a class="header-anchor" href="#「やらないこと」を定義する重要性" aria-label="Permalink to &quot;「やらないこと」を定義する重要性&quot;">​</a></h3><p>CLAUDE.mdに「やらないこと」を明記するのは最も費用対効果の高い設計判断です。LLMは放っておくとファイル整理やドキュメント追加など「改善」と称して余計なことをします。明確な境界線があるだけで、これが劇的に減ります。</p><h3 id="llmとスクリプトの責務分離" tabindex="-1">LLMとスクリプトの責務分離 <a class="header-anchor" href="#llmとスクリプトの責務分離" aria-label="Permalink to &quot;LLMとスクリプトの責務分離&quot;">​</a></h3><p>最初はすべてをLLMに任せていましたが、決定的な処理（API呼び出し、データパース、ファイルI/O）をPythonに移すことで、トークン消費と安定性が大幅に改善しました。LLMの仕事は「判断」と「生成」に限定するのが理想です。</p><h3 id="claude-mdの肥大化を防ぐ" tabindex="-1">CLAUDE.mdの肥大化を防ぐ <a class="header-anchor" href="#claude-mdの肥大化を防ぐ" aria-label="Permalink to &quot;CLAUDE.mdの肥大化を防ぐ&quot;">​</a></h3><p>肥大化するとコンテキストを圧迫し、指示の優先度も曖昧になります。最初からドメインルールはRulesに分離する方針が効果的です。CLAUDE.mdは「憲法」であり「百科事典」にすべきではありません。</p><h3 id="パーミッション設計は実運用で磨く" tabindex="-1">パーミッション設計は実運用で磨く <a class="header-anchor" href="#パーミッション設計は実運用で磨く" aria-label="Permalink to &quot;パーミッション設計は実運用で磨く&quot;">​</a></h3><p>最初からすべてを正しく設定するのは不可能です。「実行して確認が出る → 許可パターンを追加する」サイクルで、徐々に快適な設定に収束させることが現実的です。</p><h3 id="hooksはまだ使っていない" tabindex="-1">Hooksはまだ使っていない <a class="header-anchor" href="#hooksはまだ使っていない" aria-label="Permalink to &quot;Hooksはまだ使っていない&quot;">​</a></h3><p>このリポジトリではHooksを未導入です。CLAUDE.mdやRulesは「お願い」（advisory）、Hooksは「強制」（deterministic）という性質が異なります。</p><p>Hooksでできることは幅広いですが、ブロック用途では<code>settings.json</code>の<code>deny</code>で十分なケースが多いです。Hooksが必要なのは、「変更対象ファイルの中身を見てバリデーションする」など、パターンマッチでは表現できない動的な判断が求められる場面です。</p><h2 id="まとめ" tabindex="-1">まとめ <a class="header-anchor" href="#まとめ" aria-label="Permalink to &quot;まとめ&quot;">​</a></h2><p>ハーネスエンジニアリングはClaude Codeを「賢いチャットボット」から「自分専用の開発環境」に変えるアプローチです。</p><p>CLAUDE.mdでプロジェクトの憲法を定め、Rulesでドメインルールを分離し、Skillsで繰り返すワークフローを定義し、Agentsで専門的タスクを委譲し、Settingsで安全装置を整備することで、Claude Codeは会話するたびに文脈を理解し、ルールに沿って動く「自分のチーム」になります。</p><p>ハーネスが整っていれば、扱える領域はどこまでも広がります。</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><p><strong>原文語言</strong>：日文（日本工程師分享 Claude Code Harness Engineering 5 層設計實踐）</p><h3 id="核心命題-llm-是無狀態函數-harness-負責注入記憶" tabindex="-1">核心命題：LLM 是無狀態函數，Harness 負責注入記憶 <a class="header-anchor" href="#核心命題-llm-是無狀態函數-harness-負責注入記憶" aria-label="Permalink to &quot;核心命題：LLM 是無狀態函數，Harness 負責注入記憶&quot;">​</a></h3><p>LLM 本質上是「無狀態函數」——推論中模型權重不變，內部沒有記憶功能。對話看起來持續，是因為應用層每次把完整對話歷史注入提示。<strong>每次對 LLM 來說都是初次見面</strong>。</p><p>因此，專案規則、過去失敗案例、目錄結構——一切都必須每次從外部注入。設計這個注入機制的整體就是 Harness Engineering。</p><h3 id="三層工程的定位" tabindex="-1">三層工程的定位 <a class="header-anchor" href="#三層工程的定位" aria-label="Permalink to &quot;三層工程的定位&quot;">​</a></h3><table tabindex="0"><thead><tr><th>概念</th><th>對象</th><th>焦點</th></tr></thead><tbody><tr><td>Prompt Engineering</td><td>對模型的輸入文字</td><td>「問什麼」的優化</td></tr><tr><td>Context Engineering</td><td>傳遞給模型的資訊整體</td><td>「展示什麼」的優化</td></tr><tr><td><strong>Harness Engineering</strong></td><td><strong>模型外側的執行環境整體</strong></td><td><strong>「如何運作」的優化</strong></td></tr></tbody></table><p>Context Engineering 是 Harness 的一部分。</p><h3 id="_5-層設計架構" tabindex="-1">5 層設計架構 <a class="header-anchor" href="#_5-層設計架構" aria-label="Permalink to &quot;5 層設計架構&quot;">​</a></h3><table tabindex="0"><thead><tr><th>層次</th><th>角色</th><th>檔案</th></tr></thead><tbody><tr><td><strong>CLAUDE.md</strong></td><td>專案整體規則與 context（「憲法」）</td><td><code>CLAUDE.md</code></td></tr><tr><td><strong>Rules</strong></td><td>特定領域的 Domain 規則</td><td><code>.claude/rules/*.md</code></td></tr><tr><td><strong>Skills</strong></td><td>可重用的工作流定義</td><td><code>.claude/skills/*/SKILL.md</code></td></tr><tr><td><strong>Agents</strong></td><td>專門化的子代理</td><td><code>.claude/agents/*.md</code></td></tr><tr><td><strong>Settings</strong></td><td>工具權限與安全控制</td><td><code>.claude/settings.json</code></td></tr></tbody></table><h3 id="layer-1-claude-md-是「憲法」" tabindex="-1">Layer 1：CLAUDE.md 是「憲法」 <a class="header-anchor" href="#layer-1-claude-md-是「憲法」" aria-label="Permalink to &quot;Layer 1：CLAUDE.md 是「憲法」&quot;">​</a></h3><p>最重要的設計判斷：<strong>明確記載「不做的事情」</strong>。</p><p>LLM 若放任不管，會以「改善」之名進行檔案整理、加文件等多餘動作。只要有明確的邊界線，這種情況會大幅減少。「不做的事」定義的是行動範圍，不是推理抑制。</p><p>個人設定分離方式：CLAUDE.md 末尾加 <code>@my-preferences.md</code>，並將該檔放入 <code>.gitignore</code>。</p><h3 id="layer-2-rules-的條件式載入" tabindex="-1">Layer 2：Rules 的條件式載入 <a class="header-anchor" href="#layer-2-rules-的條件式載入" aria-label="Permalink to &quot;Layer 2：Rules 的條件式載入&quot;">​</a></h3><p><code>.claude/rules/*.md</code> 的讀取時機由 YAML frontmatter 的 <code>globs</code> 控制：</p><table tabindex="0"><thead><tr><th>條件</th><th>載入時機</th><th>Token 消耗</th></tr></thead><tbody><tr><td>無 <code>globs</code></td><td>Session 開始時常駐載入</td><td>常時</td></tr><tr><td>有 <code>globs</code></td><td>符合的檔案被讀取時延遲載入</td><td>條件付き</td></tr></tbody></table><p>例：API 層的 coding rule 只在處理 <code>src/api/**/*.ts</code> 時載入。</p><h3 id="layer-3-skills-的責務分離原則" tabindex="-1">Layer 3：Skills 的責務分離原則 <a class="header-anchor" href="#layer-3-skills-的責務分離原則" aria-label="Permalink to &quot;Layer 3：Skills 的責務分離原則&quot;">​</a></h3><p>關鍵設計原則：<strong>決定性處理交給 script，判斷與生成交給 LLM</strong>。</p><p>初版 <code>/tech-daily</code>（所有工作都給 LLM）→ 改善版 <code>/tech-daily2</code>（Python script 負責 RSS 取得/解析，LLM 只負責翻譯和分類）：</p><ul><li>Token 消耗減少 <strong>1/6</strong></li><li>處理時間減少 <strong>1/3</strong></li></ul><h3 id="layer-4-agents-的-context-隔離" tabindex="-1">Layer 4：Agents 的 Context 隔離 <a class="header-anchor" href="#layer-4-agents-的-context-隔離" aria-label="Permalink to &quot;Layer 4：Agents 的 Context 隔離&quot;">​</a></h3><p>子代理在與主 Claude Code 不同的 context 中運作，處理大量資訊時不會污染主 context。數百個檔案的搜尋任務，透過子代理委派只有摘要回傳。</p><h3 id="layer-5-settings-的安全設計" tabindex="-1">Layer 5：Settings 的安全設計 <a class="header-anchor" href="#layer-5-settings-的安全設計" aria-label="Permalink to &quot;Layer 5：Settings 的安全設計&quot;">​</a></h3><ul><li><strong>allow</strong>：業務需要的操作範圍廣泛許可（保持作業節奏）</li><li><strong>deny</strong>：破壞性操作明示禁止（repo 刪除、archive、PR close 等）</li><li><strong>分工</strong>：<code>settings.json</code>（通用工具，git 共享）vs <code>settings.local.json</code>（URL 固定的 curl 命令，本機專用）</li></ul><h3 id="實踐心得" tabindex="-1">實踐心得 <a class="header-anchor" href="#實踐心得" aria-label="Permalink to &quot;實踐心得&quot;">​</a></h3><ol><li><strong>CLAUDE.md 肥大化預防</strong>：Domain 規則從一開始就移到 Rules；CLAUDE.md 是「憲法」，不是「百科全書」</li><li><strong>Permission 設計靠實際運作磨礪</strong>：「執行 → 出現確認 → 加許可模式」循環，逐步收斂到舒適設定</li><li><strong>Hooks 是強制（deterministic），Rules 是建議（advisory）</strong>：只需要 Pattern Match 無法表達的動態判斷時才用 Hooks</li></ol><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>5 層架構、conditional rules with globs、/update-coding-rule skill 均直接可套用</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>LLM-as-stateless-function 框架、Rules vs Hooks 的強制/建議區分新穎</td></tr><tr><td>C. 證據品質</td><td>7/10</td><td>1/6 token、1/3 時間節省數據；Scripts vs LLM 責任分離有具體說明</td></tr><tr><td>D. 技術深度</td><td>7/10</td><td>5 層設計有細節，但每層深度有限</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>分層 config 模式適用任何 Claude Code 專案</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.45/10</strong></td><td>8×0.3+7×0.2+7×0.2+7×0.15+8×0.15 = 2.4+1.4+1.4+1.05+1.2</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/refs/harness-design.md</code>（5 層架構參考）<br><strong>整合狀態</strong>：待實作</p>`,106)])])}const u=a(i,[["render",n]]);export{g as __pageData,u as default};
